window.__LIBQ=window.__LIBQ||{};window.__LIBQ["tien-nghich"]=window.__LIBQ["tien-nghich"]||{};window.__LIBQ["tien-nghich"]["q20"]=window.__LIBQ["tien-nghich"]["q20"]||{};window.__LIBQ["tien-nghich"]["q20"]["cotTruyen"]=[{"chuong":1866,"tieuDe":"Âm Mưu Của Tiên Hoàng!","tomTat":"Một năm sau khi xông Thiên Tôn Niết, Vương Lâm với danh Bạch Phát Dược Thiên Tôn trở thành truyền kỳ mới của Tiên Tộc, được xem là Dược Thiên Tôn thứ bốn mươi chín và mạnh nhất dưới Đại Thiên Tôn. Lời đồn về Hồn Khải, sinh linh thiên ngoại, việc cự tuyệt các Đại Thiên Tôn và lựa chọn Song Tử lan rộng, khiến Tử Dương Tông nhờ hắn mà lại được chú ý. Tin tức truyền sang Cổ Tộc, khiến Huyền La vừa than thở vừa tự hào vì Vương Lâm là đệ tử mình phát hiện từ động phủ giới, còn hoàng tôn Đạo Cổ thì tiếp tục tuyển hậu thất bại và ra lệnh sưu tập tư liệu về Vương Lâm. Chương cũng nhắc lại uy thế của Cổ Đạo Đại Thiên Tôn, người từng khiến Tiên Tộc khiếp sợ và không dám tiến đánh Cổ Tộc. Ở hoàng thành Trung Châu, Minh Đạo Tôn bị đặt trong ao nước đen dưới địa cung, chịu hắc khí xâm nhập để tu Phản Cổ đại pháp theo âm mưu của Tiên Hoàng. Tiên Hoàng bộc lộ kế hoạch tái hiện huy hoàng Tiên Tổ, dùng Cửu Đế khai đao, trọng dụng Đạo Nhất, giết Võ Phong để đưa Đạo Phi lên Đại Thiên Tôn và tạm gạt Song Tử nếu chưa song hồn quy nhất. Cuối chương, Vương Lâm ngồi bên Tự Thú Giới ở Tử Dương Tông, cảm nhận màn ngăn với quê hương trong động phủ giới và hiểu rằng mình nên rời đi, trong lúc Lưu Kim Bưu bị hai cô bé trêu chọc bằng biệt danh Tiểu Bưu Tử."},{"chuong":1867,"tieuDe":"Tiên Tộc Đệ Nhất Thành!","tomTat":"Sau một năm ở Tử Dương Tông, Vương Lâm cùng Lưu Kim Bưu rời đi trong tuyết, rồi dùng súc địa thành thốn mang Lưu Kim Bưu và Hải Long rời Đông Châu. Một năm lặng tu giúp mộc bổn nguyên của hắn đại thành, lôi đình chân thân đã viên mãn, ngũ hành chân thân chỉ còn thiếu kim bổn nguyên, còn luân hồi bổn nguyên mới mở ra một tia. Cô Nhai Thiên Tôn cùng Oa Oa và Hàm Hàm tiễn hắn, đồng thời đã chuẩn bị ngọc giản để nếu Vương Lâm gặp nguy cơ ở Trung Châu thì Song Tử Đại Thiên Tôn có thể ra tay trợ giúp. Chương mở ra toàn cảnh Tổ Thành của Tiên Tộc ở Trung Châu: hoàng cung là cấm địa trung tâm, Đạo Môn là tông phái quốc sư hoàng tộc, bốn phân thành có tứ đại phủ phong vương, còn Đế Sơn của Cửu Đế Đại Thiên Tôn tạo áp lực lên hoàng quyền. Đạo Môn được giới thiệu là thế lực thần bí truyền thừa xa xưa, đời này do Tiên Hoàng Liên Đạo Chân đặt tên và do quốc sư Thượng Đạo Huyền làm tông chủ. Vương Lâm tới ngoài Đông môn Tổ Thành vì mảnh vỡ Tiên Cực Kiếm và vì muốn gặp lại người điên từng có ân với hắn ở Chu Tước Tinh. Dù biết nơi này nguy hiểm và quy củ trong thành áp chế mọi tu sĩ, hắn vẫn bước vào Tổ Thành, tự khẳng định quy củ ấy không bao gồm mình."},{"chuong":1868,"tieuDe":"Lý Phủ!","tomTat":"Trong Đông Thành của Tổ Thành, Lý Phủ bất ngờ phát sinh dị biến khi giá cung màu tím trong mật thất reo vang, khiến lão già trấn giữ nhận định cung của lão tổ đang xuất hiện gần đó. Ông ta sai Lý Vân và Lý Sơn theo mũi tên màu tím dò khí tức cây cung, mở đầu hành động của Lý gia. Vương Lâm đi trong gió tuyết Đông Thành, thuê một gian phòng có tiên khí, cấm chế và phong ấn để tạm nghỉ, rồi cho Lưu Kim Bưu mang Hải Long ra ngoài tìm Hứa Lập Quốc. Khi còn lại một mình, hắn uống rượu nhớ Liên Đạo Phi và chuyện trong động phủ giới. Trên đường trong đêm, Vương Lâm bị tu sĩ Lý gia dùng mũi tên màu tím và cung ảnh tập kích, nhưng hắn chỉ điểm một chỉ đã phá tan đòn công kích, khiến đối phương phải dùng thuật huyễn động hóa huyết ảnh bỏ chạy. Vương Lâm suy đoán cây cung của Lý Quảng trong thân thể mình khiến Lý gia cảm ứng được, nên không truy sát vì giữa hai bên chưa có thù oán. Sau đó hắn phát hiện Hứa Lập Quốc trong một lầu các đèn hoa, nhận ra đối phương bị người khác đặt phong ấn và có nhiều tu sĩ bước thứ ba hộ vệ. Khi đang định vào gặp Hứa Lập Quốc, Vương Lâm cảm thấy Lý Phủ tiếp tục hành động quá mức, bèn lạnh lùng rời đi để xử lý."},{"chuong":1869,"tieuDe":"Tên!","tomTat":"Trên đường Đông Thành, Lưu Kim Bưu cưỡi Hải Long bỏ chạy trong tình trạng Hải Long trọng thương vì một mũi tên màu đen phá hủy sinh cơ. Kẻ truy kích áo đen của Lý Phủ tiếp tục bắn mũi tên thứ hai, nhưng Vương Lâm đột ngột xuất hiện trước mặt hai người, chỉ ngẩng đầu đã phá nát mũi tên và khiến kẻ truy sát hộc máu hôn mê. Vương Lâm chữa thương cho Hải Long, bóp nát mũi tên đen, dùng thần thức lấy tin tức từ nam tử trung niên rồi xác định Lý Phủ là nơi phải tới hỏi tội. Hắn đưa Lưu Kim Bưu, Hải Long và tù binh tới trước Lý Phủ, sai Lưu Kim Bưu gõ cửa gọi chủ nhân phủ ra, khiến Lưu Kim Bưu phấn khích đá bật đại môn. Khi Vương Lâm bước vào, hai sư tử đá trấn môn hóa hư ảnh công kích nhưng lập tức tan biến và nứt vỡ. Bên trong Lý Phủ, mấy trăm người đồng loạt bắn tên lập tiễn trận, bị Vương Lâm phất tay hóa chưởng ấn đánh sụp. Ngay sau đó, chín vị trí trong phủ bắn ra chín mũi tên hóa thành mưa tên và bàn tay khổng lồ, nhưng Vương Lâm chỉ điểm một chỉ khiến toàn bộ công kích dừng lại trước mặt."},{"chuong":1870,"tieuDe":"Bạch Phát Dược Thiên Tôn!","tomTat":"Vương Lâm đối mặt thế trận cung tiễn của Lý Phủ, nhìn ra chín Thiên Tôn cùng ba cao thủ ẩn giấu phía sau, rồi lạnh lùng cảnh cáo nếu họ tiếp tục ra tay thì hắn sẽ không còn nương tay. Khi Lý Phủ vẫn muốn ép hắn, hắn vận kim quang mang uy áp Tiên Cực Kiếm, chỉ bằng ánh mắt đã trấn áp toàn phủ, khiến cung của tộc nhân và các Thiên Tôn lần lượt vỡ nát, buộc người trong thạch thất phải hiện thân. Lão tổ Lý gia bước ra, nhận ra hắn chính là Bạch Phát Dược Thiên Tôn đang chấn động Tiên Tộc, khiến toàn bộ Lý Phủ kinh hãi và lập tức đổi thái độ. Lão tổ giải thích mọi chuyện bắt nguồn từ tiếng cung reo của giá cung tổ tiên, thừa nhận tộc nhân lỗ mãng, rồi mời Vương Lâm ở lại Lý Phủ, mở Tiễn Các cho hắn tùy ý xem Tiễn Đạo để bồi lỗi. Vương Lâm lấy cung Lý Quảng ra, làm lão tổ Lý gia kích động, nhưng hắn chỉ hứa sau khi giải quyết xong việc của mình sẽ gửi trả lại cây cung này. Sau đó Vương Lâm lưu lại Tiễn Các nghiên cứu Tiễn Đạo, còn Lưu Kim Bưu nhờ thân phận đi theo hắn mà được Lý gia tiếp đãi trọng hậu. Ba ngày sau, sứ giả Tiên Hoàng đến truyền chỉ, yêu cầu Vương Lâm bảy ngày nữa tới Tiên Đạo Điện trong hoàng cung dự đại lễ sắc phong Dược Thiên Tôn. Nhận chỉ xong, Vương Lâm nghĩ tới những biến số trong nghi lễ, đặc biệt là Liên Đạo Chân và khả năng gặp người điên, rồi dùng thần thức quét Đông Thành nhưng không thấy Liên Đạo Phi."},{"chuong":1871,"tieuDe":"Nếp Nhăn Năm Tháng","tomTat":"Sáng sớm tại hoàng cung Tiên Tộc trong Tổ Thành, mấy vạn tu sĩ, trọng thần, gia tộc, Thiên Tôn và Dược Thiên Tôn tụ hội trước Tiên Đạo Điện để xem lễ sắc phong Bạch Phát Dược Thiên Tôn cho Vương Lâm. Hắc giáp cấm binh của hoàng tộc xếp thành hai hàng dẫn ra cửu môn, rồi một lão già mặc thanh y từ Tiên Đạo Điện bước ra tuyên bố giờ lành đã tới và đóng cửu môn, khiến hắc quang nối lại thành thông đạo khảo nghiệm. Vương Lâm áo trắng tóc bạc xuất hiện tại đệ nhất môn, dáng vẻ vẫn trẻ nhưng nếp nhăn nơi đuôi mắt lộ rõ tang thương và mệt mỏi của năm tháng. Lão thanh y gọi tên hắn, nói hắn phải đi qua cửu môn tới trước mặt lão thì đại lễ mới bắt đầu, sau đó Tiên Hoàng sẽ tự sắc phong và quốc sư sẽ tính toán tương lai cho hắn, còn trận pháp hoàng cung sẽ truyền chiếu toàn bộ diễn biến tới các tông môn trong bảy mươi hai châu. Vương Lâm biết cửu môn vốn chỉ là nghi thức tượng trưng nhưng vẫn đề phòng, rồi nhận ra khảo nghiệm lần này là sát khí của mười vạn hắc giáp cấm binh. Hắn vận sát lục lôi đình lực đẩy lui hắc quang quanh thân, sau đó dùng Thiên Ngưu Hồn và Hồn Khải đánh tan hư ảnh mãnh hổ cùng thông đạo đen, khiến mười vạn cấm binh phun máu lui lại nhưng không chết. Cuối cùng hắn đi tới trước Tiên Đạo Điện, ánh mắt khiến lão thanh y hoảng sợ lui lại, rồi lạnh lùng quát lão cũng phải lui ra."},{"chuong":1872,"tieuDe":"Tiên Hoàng Tứ Bảo!","tomTat":"Trước đại lễ sắc phong, lão già mặc thanh y tiếp tục khiêu khích Vương Lâm nhưng lập tức bị hắn túm ném ra ngoài mấy vạn trượng, khiến toàn trường chấn động. Tiên Hoàng mở cửa Tiên Đạo Điện, ngồi trên long ỷ và bỏ qua việc này vì xem lão già kia là nô tài bất kính với đệ nhất Dược Thiên Tôn. Bên cạnh Tiên Hoàng, Thượng Huyền Đạo quốc sư lộ diện với hạt châu tím trong tay, ánh mắt khiến Vương Lâm thoáng như nhìn thấy cả đời mình lướt qua. Theo lệnh Tiên Hoàng, quốc sư dùng huyết tế tiên mở tiên đạo, khiến chín mươi chín huyết trụ và thú hồn phóng lên, dẫn một Thiên Sư Thú bị thương từ hư vô tới đại lễ. Tiên Hoàng dùng lửa năm màu thiêu chết Thiên Sư Thú trước toàn trường, phô diễn thần uy khiến tu sĩ quỳ lạy. Sau biển lửa, một sợi tóc bạc rơi xuống, không bị Cực Hỏa Đạo đốt cháy và còn xuyên thủng bàn tay lửa của Tiên Hoàng. Vương Lâm cảm thấy sợi tóc này quen thuộc, lập tức lao lên đoạt lấy rồi cảm tạ Tiên Hoàng như nhận bảo vật được ban."},{"chuong":1873,"tieuDe":"Người Điên!","tomTat":"Sợi tóc bạc rơi vào tay Vương Lâm khiến hắn có cảm giác quen thuộc như một bộ phận thân thể mình, và Tiên Hoàng cho phép hắn giữ lại trong bối cảnh đại lễ sắc phong. Thượng Huyền Đạo quốc sư tuyên bố huyết tế kết thúc, đại lễ bước vào giai đoạn cuối với tối đa ba lần khiêu chiến Vương Lâm trước khi sắc phong. Một lão già hồng bào thuộc nhóm lão tổ vương phủ ngoài Lý Phủ ra tay, dùng hắc khí, máu tươi rồi hiến tế thọ nguyên và sinh cơ để ngưng bóng đen giáp trụ cùng chiến mã, nhưng bị Vương Lâm dùng Thiên Ngưu Hồn Khải và Thiên Ngưu Chàng đánh tan. Hư ảnh Thiên Ngưu sau đó lao về phía Thượng Huyền Đạo, và quốc sư chỉ một cái, giảng về đạo “vô” khiến nó tan biến, làm Vương Lâm nhận ra đạo pháp của ông cực kỳ đáng sợ. Khi chuẩn bị gọi người khiêu chiến thứ hai, Đạo Phi xuất hiện từ Truyền Tống Trận ngoài cửu môn hoàng cung cùng Hứa Lập Quốc và thiếu niên thanh y, gây náo loạn vì cho rằng không ai báo cho mình chuyện náo nhiệt. Hứa Lập Quốc bị ép mở đường rồi giả chết, còn Đạo Phi thấy La Công già yếu thì tưởng quốc sư bắt nạt gia gia của Tiểu Hoa nên định xông tới bóp cổ Thượng Huyền Đạo. Tiên Hoàng bất đắc dĩ gọi tên Đạo Phi, dùng lực lượng nhu hòa đẩy hắn ra và nhắc rằng đây là đại lễ sắc phong của ân công hắn, khiến Đạo Phi sững sờ."},{"chuong":1874,"tieuDe":"Giết Chóc Ẩn Trong Gió Tuyết!","tomTat":"Thanh niên áo hoa Đạo Phi xuất hiện giữa không trung, nhận nhầm Vương Lâm là ân công nhưng ánh mắt lại không còn ký ức về hắn. Vương Lâm hạ xuống gọi hắn là Người điên, nhận ra ký ức trong động phủ giới của Đạo Phi đã mất nên sinh bi thương. Đạo Phi rối loạn, vừa truy hỏi ai đánh gia gia của Tiểu Hoa, vừa bị Tiên Hoàng từ trong Tiên Đạo Điện quát mắng và giải thích La Công tự khiêu chiến thất bại. Thiếu niên áo xanh cố kéo Đạo Phi rời đi bằng chuyện lò đan dược định tặng Hải Tử Thiên Tôn, nhưng Đạo Phi lại gọi Hứa Lập Quốc dậy hỏi chuyện. Hứa Lập Quốc nhìn thấy Vương Lâm thì linh hồn run rẩy, theo tiềm thức gọi Sát tinh chủ và suýt thức tỉnh ký ức, song bị Đạo Phi lay tỉnh rồi sợ hãi chỉ Vương Lâm là thủ phạm. Đạo Phi nổi giận bóp cổ Vương Lâm, còn Vương Lâm nhắm mắt chịu đựng trong bi thương. Cuối cùng Tiên Hoàng bước ra, vung tay đẩy Đạo Phi lui và ra lệnh hắc giáp cấm binh tống hắn khỏi hoàng cung, nhưng Đạo Phi vẫn ghi hận Vương Lâm vì chuyện La Công."},{"chuong":1875,"tieuDe":"Giết Chóc Ẩn Trong Gió Tuyết! (2)","tomTat":"Sau khi Đạo Phi rời đi qua truyền tống trận, Tiên Hoàng giải thích rằng Đạo Phi sau khi trở về thì trí nhớ lúc tỉnh lúc mê, có lẽ chỉ khi tỉnh táo mới nhận ra Vương Lâm. Tiên Hoàng bỏ nghi thức khiêu chiến, chính thức sắc phong Vương Lâm làm Dược Thiên Tôn thứ bốn mươi chín của tiên tộc với danh hiệu Bạch Phát Dược Thiên Tôn, rồi mời hắn vào nơi bế quan của tiên tổ cảm ngộ. Vương Lâm cảm tạ nhưng từ chối, vì mục đích sắc phong đã hoàn tất và hắn vẫn giữ cảnh giác trước Tiên Hoàng. Rời hoàng cung, hắn không ở Lý Phủ mà đưa Hải Long và Lưu Kim Bưu về tửu lâu phía đông thành, tự nhủ gặp lại Đạo Phi như vậy đã đủ rồi và quyết định mang Hứa Lập Quốc rời tổ thành tiên tộc để đi cổ tộc. Trong gió tuyết, Hải Tử Thiên Tôn tới mời Vương Lâm đến Đế Sơn theo lệnh Cửu Đế Đại Thiên Tôn, hắn nhận lời và cùng nàng đi tới truyền tống trận. Trên con phố dài tối om, sát khí ẩn trong tuyết bỗng nổi lên, Vương Lâm cảm thấy nguy cơ mãnh liệt còn Hải Tử Thiên Tôn nhận ra dao động phong ấn giam cầm."},{"chuong":1876,"tieuDe":"Phố Dài!","tomTat":"Vương Lâm và Hải Tử Thiên Tôn dừng lại trên phố dài cổ kính giữa gió tuyết thì sát cục lập tức mở ra, tuyết phía trước ngưng thành đồ án bốn cạnh còn phía sau thành đồ án ba cạnh. Vương Lâm chọn tin Hải Tử Thiên Tôn, tự mình đối phó hướng trước và để nàng chặn hướng sau. Hắn mặc Thiên Ngưu Hồn Khải, dùng một quyền dung hợp nhiều tầng thần thông đánh tan đồ án bốn cạnh, nhưng lực lượng Vô trong đồ án chui vào cơ thể, hóa thành lưới phong ấn khiến thân thể bị giam cầm. Đúng khoảnh khắc đó, mười lăm Thiên Tôn từ các hướng lao ra vây sát; Vương Lâm dựa vào Hồn Khải, lực Đạo cổ và thân thể cường hãn phản kích giết ba người phía sau. Mười hai người còn lại tiếp tục phối hợp huyết độn, điểm chỉ tăng phong ấn và ngân kiếm từ trên cao, khiến một kiếm đâm vào thiên linh Vương Lâm ba tấc, máu chảy phủ mắt nhưng hắn vẫn tỉnh táo. Phía sau, Hải Tử Thiên Tôn bị chín người không có sát khí vây giữ, không thể tới cứu viện. Trước mặt Vương Lâm lại xuất hiện ba hư ảnh đen từ dưới đất và chín thân ảnh hợp lực tạo băng long, nhưng hắn bộc phát sát khí, hiển hóa Thiên Ngưu khổng lồ húc nát băng long. Chương khép lại khi băng long tan vỡ, chín người bị cuốn bay, nhưng cuộc giết chóc trên phố dài vẫn chưa chấm dứt."},{"chuong":1877,"tieuDe":"Huyết Chiến!","tomTat":"Thiên Ngưu hiện ra quanh Vương Lâm, phá tan khối băng và phản chấn nhóm mười hai thân ảnh đang vây công, rồi tiếp tục nuốt ba hắc ảnh và lao xuyên nhóm hóa băng long trước khi nổ tung ở cuối đường. Vương Lâm hóa thành sương đen, hút sạch tinh khí, huyết nhục và nguyên thần của nhiều nhóm địch, giải vây cho Hải Tử Thiên Tôn và khiến phố tuyết chỉ còn hài cốt khô héo. Sau đó hắn nhận ra hơn ba mươi kẻ vừa chết không phải Thiên Tôn bình thường mà là người bị cưỡng ép nâng tu vi trong một canh giờ, đồng thời suy đoán sát cục đã phong tỏa chiến trường và tính cả cứu viện của Cửu Đế Đại Thiên Tôn. Đợt sát kích thứ hai xuất hiện với ba áo trắng gần Dược Thiên Tôn và hai Hồn khải sứ giả áo đen cấp Dược Thiên Tôn, nên Vương Lâm đẩy Hải Tử lùi lại để một mình nghênh chiến. Ba áo trắng dùng gió tuyết bạo và tự bạo, hai áo đen dùng hắc phong hóa hắc xà, nhưng cuối cùng đều bị Vương Lâm giết khiến hắn cũng bị thương nặng. Khi hắn chống cốt âm đao xuống đất, một bàn tay bí ẩn vô thanh vô tức hiện sau lưng điểm vào gáy, lộ ra kẻ bố trí đồ án giam cầm. Vương Lâm đã chờ thời khắc này, để cốt âm đao vỡ thành mảnh, dùng phân thân cực mạnh ẩn trong hư vô phát kim quang phá giam cầm rồi lập trận bằng mảnh đao. Chương kết thúc khi hắn giơ tay trái dùng một chỉ đối đầu với ngón tay bí ẩn vừa xuất hiện."},{"chuong":1878,"tieuDe":"Không Đi!","tomTat":"Trong con phố gió tuyết bị giam cầm, Vương Lâm dốc toàn bộ chiến lực hiện có vào một chỉ, kết hợp phân thân trong hư vô, Hồn Khải, các chân thân, bổn nguyên và mảnh vỡ cốt âm đao để đối kháng ngón tay thần bí. Ngón tay ban đầu bị đánh tan nhưng giọng nói bình tĩnh dùng đạo Hữu/Không khiến nó tái ngưng tụ và hóa giải nhiều tầng lực lượng của Vương Lâm, chỉ còn tam đại hư bổn nguyên và kim quang phân thân hư vô không bị xua tan. Khi Vương Lâm lui tới cuối phố để phá giam cầm, gần trăm tử sĩ xuất hiện trên mái nhà hai bên, dùng máu và sinh mạng bắn hơn trăm mũi tên máu về phía hắn. Vương Lâm thi triển Tàn Dạ, hóa cảnh thành biển đêm và mặt trời bình minh để phá phần lớn mũi tên và làm ngón tay sụp đổ, nhưng vẫn bị bảy mảnh tên xuyên qua thân thể. Sau đó hắn đánh vào biên giới giam cầm và thấy bên ngoài con phố có mấy vạn tu sĩ hắc bào hợp lực tạo vòng bảo hộ, còn chủ nhân giọng nói tuyên bố tông môn đã dùng lực lượng mạnh nhất để giết hắn. Khi hơn trăm tu sĩ hắc bào tiếp tục hiến thân, nguyên thần hóa thành trăm thân ảnh Thiên Tôn lao vào phố, Vương Lâm quyết định không chạy nữa mà giết sạch để phá cục. Cuối chương, hắn để sát lục thân phủ xuống, lần đầu buông lỏng cấm chế cho sát lục lôi đình chân thân và Thái Sơ bổn nguyên, khiến sát lục lôi đình bổn nguyên trong cơ thể trở thành chủ đạo."},{"chuong":1879,"tieuDe":"Vương Lâm Tóc Đen!","tomTat":"Trong trận chiến trên con đường đêm tuyết, Vương Lâm mở mắt trong trạng thái hoàn toàn khác lạ: đồng tử đen kịt, tóc chuyển đen, khí chất tàn nhẫn khiến Hải Tử Thiên Tôn hoảng sợ lùi lại. Hắn dùng sát lục lôi đình màu đen tạo thành lưới, phá các đợt tự bạo và nghiền nát lớp tử sĩ đầu tiên. Khi trăm tử sĩ kết trận dẫn địa khí hóa thành bàn tay đen, Vương Lâm dùng hàng trăm đạo lôi đình đánh vỡ cả trận, rồi tiếp tục phá ngón tay hư vô muốn khiến mọi thứ thành Vô. Trước các lớp thân ảnh tiếp tục xuất hiện, hắn chủ động vứt Thiên Ngưu Hồn Khải, rồi bức Ngũ hành chân thân cùng nhiều bổn nguyên như cấm chế, thái sơ, lôi đình, sinh tử, nhân quả, chân giả rời khỏi cơ thể. Khi bản thể chỉ còn Mặc Diệt và sát lục, hắc khí quanh hắn co lại thành trường bào đen, và chỉ một lần mở mắt đã khiến mấy vạn thân ảnh vô thanh vô tức hóa thành mây khói. Sau đó hắn kéo thân ảnh ánh sáng trắng khỏi hư vô, khẳng định kẻ này không phải quốc sư rồi bóp nát. Chứng kiến toàn bộ biến hóa ấy, Hải Tử Thiên Tôn kinh hãi hỏi hắn không phải Vương Lâm thì là ai, trong khi Vương Lâm tóc đen lạnh lùng tiến về phía nàng."},{"chuong":1880,"tieuDe":"Hải Tử Trầm Mặc","tomTat":"Vương Lâm trong trạng thái tóc đen hiện thân trước Hải Tử Thiên Tôn, phủ nhận tên Vương Lâm và tự xưng đúng ra là Lục Mặc. Hắn thu hồi ngũ hành chân thân cùng các bổn nguyên, rồi chất vấn Hải Tử là mồi nhử trong sát cục, có liên hệ với nhất mạch quốc sư và có thể đến từ thiên ngoại. Khi hắn định diệt sát Hải Tử, Cửu Đế Đại Thiên Tôn xuất hiện cứu nàng và giao thủ với Vương Lâm tóc đen bằng tuyết kiếm, hắc khí và ấn ký ánh sáng. Cửu Đế nhận ra lực lượng sát lục và hủy diệt trên người hắn, sau đó dùng mảnh vỡ Tiên Cực kiếm có thể giúp kim bổn nguyên đại thành để dàn xếp, rồi mang Hải Tử rời đi. Bình minh tới, Vương Lâm trở lại tóc bạc và nhận ra từ nay ban ngày hắn là tóc bạc, đêm xuống là tóc đen, nhờ phân thân trong hư vô mới còn giữ được thanh tỉnh. Hắn nhận mảnh vỡ Tiên Cực kiếm, bỏ lại Hồn Khải, tạm gác bí ẩn Tiên tộc và rời Tổ Thành. Sáng hôm sau, tại cửa đông, Vương Lâm cùng Lưu Kim Bưu và Hài Long chờ Hứa Lập Quốc cùng Liên Đạo Phi tới; lời gọi của hắn khiến phong ấn ký ức trong Hứa Lập Quốc tan ra."},{"chuong":1881,"tieuDe":"Trên Núi Có Hổ!","tomTat":"Hứa Lập Quốc nhìn thấy Vương Lâm liền hoàn toàn khôi phục ký ức trước khi rời động phủ giới đầu thai chuyển thế, nhớ lại thân phận ma đầu bị luyện hóa và lập tức nhận lại chủ nhân cũ. Hắn tranh vị trí thân cận với Lưu Kim Bưu, phủi bỏ người điên dù trước đó bị gọi là Tiểu Hồng, khiến người điên đau khổ và nổi giận với Vương Lâm. Khi Vương Lâm định rời đi, phong ấn ký ức trong đầu người điên nới lỏng, hắn nhớ lại động phủ giới, chuyện từng cứu thi thể Vương Lâm và nghi vấn ca ca đã phong ấn ký ức của mình. Tiếng gọi Vương Lâm và sư tôn khiến Vương Lâm quay lại, nhưng Tiên Hoàng xuất hiện từ vòng xoáy màu vàng, làm Đạo Phi mê man, xóa dấu chưởng ấn trên cánh tay và đưa hắn tới nơi bế quan của tiên tổ. Vương Lâm suy ra đó là địa cung dưới hoàng cung, cũng là cái bẫy Tiên Hoàng dùng Đạo Phi làm mồi để ép hắn quay lại. Dù biết nguy hiểm, Vương Lâm vẫn thu Hứa Lập Quốc, Lưu Kim Bưu và Hải Long vào không gian trữ vật rồi một mình trở lại tổ thành."},{"chuong":1882,"tieuDe":"Đi Tới!","tomTat":"Trong gió tuyết sáng sớm ở Tổ Thành, Vương Lâm đứng dưới cửa đông và bóp vỡ ngọc giản ước định giữa hắn với Song Tử Đại Thiên Tôn và Cô Khai Thiên Tôn. Ánh sáng tím hóa thành trận pháp, đưa Song Tử Đại Thiên Tôn tới trước mặt hắn; sau khi nhắc lại lời hứa, Vương Lâm nhờ họ vây khốn Tiên Hoàng một ngày để hắn xuống địa cung. Song Tử nhận lời, bay tới hoàng cung và giao chiến với Tiên Hoàng, khiến trên trời hiện ra mặt trời tím và mặt trời vàng. Vương Lâm thì chủ động buông thả sát lục và hủy diệt, tóc trắng hóa đen, tuyết trắng biến thành tuyết đen, bóng tối ăn mòn đường hắn đi qua. Hắn cho rằng Tiên Hoàng đã dùng Đạo Phi ép hắn tới đây nên quyết định tiến vào hoàng cung để hủy diệt. Trước hoàng cung, mấy vạn hắc giáp cấm binh hợp sát khí thành Long Quỷ chặn đường, nhưng Long Quỷ bị mây đen của Vương Lâm áp đảo và sụp đổ. Cuối cùng toàn bộ hắc giáp cấm binh chết thành hài cốt rồi hóa tro bụi, còn cửa hoàng cung và kiến trúc xung quanh cũng mục nát trong hắc ám."},{"chuong":1883,"tieuDe":"Quốc Sư!","tomTat":"Vương Lâm đứng trước các tu sĩ tiên tộc đang kinh hãi, biến màn hắc ám thành hắc tuyết rơi xuống hoàng cung khiến nơi này nhanh chóng xuống cấp. Pho tượng Tiên Tổ phát kim quang, kích hoạt trận pháp mạnh nhất của hoàng cung để ngăn hủy diệt, đồng thời quốc sư áo trắng hiện thân trước Vương Lâm. Vương Lâm thử quốc sư bằng một cước phá địa, nhưng quốc sư dùng năng lực thành Vô xóa sạch các khe nứt rồi giải thích phân thân từng bị giết trên phố bằng Đạo Diễn Hồn. Quốc sư tiết lộ Vương Lâm là trường hợp chưa từng có từ động phủ giới bước ra bằng thân thể thật, đồng thời nói thần thông mở động phủ giới vốn thuộc tộc hắn và được truyền ra sau khi tộc này đi theo Tiên Tổ. Hắn đổi không gian hoàng cung thành địa cung, để lộ tế đàn, ao máu chứa Minh Đạo Tôn và người điên bị chín xích xuyên thân. Quốc sư nói Tiên Hoàng chuẩn bị Phản tổ đại pháp để giúp Minh Đạo Tôn nhận tu vi Tiên Tổ, còn hắn muốn chọn Vương Lâm thay thế. Vương Lâm cắt lời, chỉ ra quốc sư không thể rời tổ thành hoặc hoàng cung, khiến quốc sư thừa nhận tộc mình bị Tiên Tổ phong ấn truyền thừa và bị các đời Tiên Hoàng nắm sinh tử. Cuối chương, quốc sư kể mình lợi dụng sự đa nghi của Đạo Chân để giữ Vương Lâm sống tới hôm nay, chờ lúc hai Đại Thiên Tôn giao chiến che giấu biến động để nói ra kế hoạch trong địa cung."},{"chuong":1884,"tieuDe":"Tin Ta Một Lần!","tomTat":"Quốc sư nói truyền thừa trong địa cung không đơn giản, mục tiêu cuối cùng có thể là khiến Tiên Hoàng hoặc chính quốc sư đạt tới tu vi Tiên Tổ. Hắn giải thích Tiên Hoàng đã chuẩn bị nhiều năm trên người Minh Đạo Tôn, dùng ao máu, chấp niệm hận Vương Lâm và thủ đoạn phản tổ để biến Minh Đạo Tôn thành Tiên Tổ đời thứ hai rồi khống chế. Quốc sư đề nghị tự mình chủ trì nghi thức, chuyển phần tu vi vốn dành cho Minh Đạo Tôn sang Vương Lâm, đổi lại Vương Lâm sau khi thành công phải giải phong ấn cho tộc hắn, giúp họ thoát kiếp nô phó và rời Tiên Cương đại lục. Để lấy lòng tin, hắn lập thệ phù trước pháp tắc Tiên Cương, giao mệnh tinh của tộc mình cho Vương Lâm và vì mất vật ấy mà già nua suy kiệt. Vương Lâm không hoàn toàn tin nhưng lập huyết thệ có điều kiện, nói nếu lời quốc sư là thật thì sẽ giúp một lần, đồng thời yêu cầu cứu Liên Đạo Phi trước nhưng bị từ chối vì chín sợi xích do Tiên Hoàng bố trí. Khi bước xuống ao máu, Vương Lâm bí mật thả một tia khí tức sát lục theo nước ao chui vào cơ thể Minh Đạo Tôn. Ngay lúc quốc sư chuẩn bị thi triển bí thuật, Minh Đạo Tôn mở mắt, vẻ mê mang hóa điên cuồng, khí lạnh lan khắp địa cung và nước ao nhanh chóng đóng băng."},{"chuong":1885,"tieuDe":"Tiên Lô Hóa Sơn!","tomTat":"Minh Đạo Tôn thức tỉnh trong ao đã đóng băng, thân thể dị biến và mất thần trí, lập tức mang sát khí điên cuồng nhắm vào Vương Lâm. Vương Lâm dùng huyết thệ nổ thành huyết vụ mang khí tức bản thân phủ quanh quốc sư, khiến Minh Đạo Tôn nhận nhầm mục tiêu và lao sang công kích Thượng Huyền Đạo. Nhân lúc quốc sư bị cuốn vào giao chiến, Vương Lâm lao tới tế đàn cứu Liên Đạo Phi, nhưng kim quang trên người Liên Đạo Phi và chín sợi xích bộc phát, ép hắn tan trạng thái tóc đen trở lại tóc bạc. Vương Lâm từ đó nghi ngờ người được Tiên Hoàng lựa chọn rốt cuộc là Minh Đạo Tôn hay Liên Đạo Phi, trong khi Minh Đạo Tôn cũng bộc phát kim quang và thân thể thối rữa. Quốc sư đề nghị cùng Vương Lâm trấn áp Minh Đạo Tôn để chuyển lực lượng phản tổ, còn Vương Lâm triển khai Hồn Khải, Tàn Dạ và Đạo cổ vô tiên thuật phối hợp với chín thân ảnh ánh trắng của quốc sư. Một chưởng ấn màu vàng mang lực lượng Đại Thiên Tôn từ bầu trời hoàng cung đánh xuống, quát Thượng Huyền Đạo phản bội và phá vỡ địa cung. Quốc sư mở ao nước thành dòng xoáy, kéo Vương Lâm rơi vào không gian bên dưới địa cung, nơi có bầu trời màu máu, sáu ngọn núi kỳ dị và một ngọn núi hình đầu lâu mang tướng mạo Tiên Tổ."},{"chuong":1886,"tieuDe":"Tiên Sơn!","tomTat":"Vương Lâm và Thượng Huyền Đạo lần lượt đáp xuống Cửu Tọa tiên sơn trong không gian dưới địa cung, đúng lúc chưởng ấn vàng của Tiên Hoàng giáng xuống nhưng bị đôi mắt ngọn núi hình đầu Tiên Tổ hấp thu. Tiếng gầm của Tiên Hoàng bị tiếng hai cô bé thay thế, cho thấy Song Tử Đại Thiên Tôn đang ngăn ông tiếp cận, nên quốc sư thúc Vương Lâm nhanh chóng chế phục Minh Đạo Tôn để chuyển truyền thừa. Minh Đạo Tôn xuất hiện trong trạng thái thân thể thối rữa, xương đen lộ ra vì kim quang trong cơ thể, rồi điên cuồng lao vào ngọn núi nơi Vương Lâm đứng. Quốc sư giải thích Cửu Tọa tiên sơn là tiên sơn cổ bảo vệ tiên tộc, trấn áp sinh linh trên bảy mươi hai châu, là nơi truyền thừa danh hiệu Bát Cực và cũng là cấm cung dưới địa cung hoàng cung, nơi Tiên Tổ bế quan. Sau đó quốc sư dùng thân ảnh trắng và huyết nhân, còn Vương Lâm thi triển Tàn Dạ để cùng vây công Minh Đạo Tôn, nhưng biến hóa Phản tổ đại pháp khiến huyết nhục Minh Đạo Tôn nổ tung và ba khối chứa lực Tiên Tổ đánh trúng Vương Lâm. Quốc sư tiếp tục hao tổn sinh mạng, Vương Lâm kích phát Thiên Ngưu Hồn Khải tới đỉnh điểm đánh ra một quyền hóa chân thân Thiên Ngưu, khiến Minh Đạo Tôn chỉ còn xương đen và quầng sáng vàng truyền thừa Tiên Tổ. Khi Minh Đạo Tôn phát thần niệm không cam lòng và xương cốt nát bấy, lực trùng kích khiến Vương Lâm cảm thấy nguy cơ sinh tử, còn quốc sư dùng chút sinh mạng cuối làm thân thể tan nát, hóa u quang lao thẳng tới Minh Đạo Tôn."},{"chuong":1887,"tieuDe":"Hắn, Liên Vân Quyết!","tomTat":"Sau khi khớp xương Minh Đạo Tôn nổ tung, dư lực mang sức mạnh Tiên Tổ vừa đánh quốc sư vừa cuốn tới Vương Lâm, buộc hắn làm vỡ Thiên Ngưu Hồn Khải để hóa thành chân thân Thiên Ngưu chống đỡ. Vương Lâm thấy kim quang của Minh Đạo Tôn đang ngưng tụ thân thể, còn quốc sư hóa thành u quang nói muốn dùng sinh mệnh cuối cùng giúp hắn nhận truyền thừa Tiên Tổ. Không tin quốc sư vì từng bị cuốn vào sát cục trên phố, Vương Lâm dồn sức cuối của Thiên Ngưu tung một quyền đánh sụp thân ảnh vàng đang thành hình. Quốc sư phẫn nộ triệu hồi đầu Tiên Tổ từ ngọn núi hình đầu, để lộ di hài Liên Vân Quyết với uy áp kinh thiên động địa. Chương xác nhận Liên Vân Quyết là thủy tổ Tiên hoàng, thủy tổ Tiên tộc, người từng trấn áp bảy mươi hai sinh linh thiên ngoại và sáng tạo Thiên Tôn Niết. Đốm sáng vàng của Minh Đạo Tôn nhập vào mắt phải đầu Tiên Tổ, rồi Vương Lâm cũng bị kim quang từ mắt phải hút vào. Bên trong, quốc sư lộ rõ ý đồ thật: dùng sức mạnh Tiên Tổ trấn áp tâm thần Vương Lâm, chiếm thần trí và thân thể hắn để gián tiếp đoạt tu vi Tiên Tổ."},{"chuong":1888,"tieuDe":"Giải Phong Ấn Điệu Vong Tộc!","tomTat":"Trong cấm cung Tổ thành, đầu lâu Tiên Tổ lơ lửng giữa tám ngọn núi, mắt phải chứa một thế giới đen tối nơi Vương Lâm đang bị kim quang truyền thừa xâm chiếm. Kim quang cải tạo thân thể hắn và bị Thượng Huyền Đạo lợi dụng để trấn áp tâm thần, nhưng hồn huyết Cổ Tổ trong cơ thể Vương Lâm vẫn không bị lấn át hoàn toàn. Thượng Huyền Đạo chỉ còn thần thức, tưởng rằng đã dùng thuật hóa hư làm linh hồn Vương Lâm tan biến và đoạt được thân thể hắn. Sau đó hắn bộc lộ mục tiêu thật là giải thoát tộc nhân Điệu Vong tộc khỏi phong ấn của Tiên Tổ, dù bản thân phải hình thần câu diệt. Hắn dùng thân thể Vương Lâm kích hoạt mắt phải, niệm chú mở mắt trái Tiên Tổ, tạo lực hút kéo Liên Đạo Phi khỏi tế đàn, khiến chín sợi xích sắt khóa hắn lần lượt đứt hết. Khi Liên Đạo Phi bị nuốt vào mắt trái, hai mắt đầu lâu Tiên Tổ cùng phát kim quang và cái miệng vốn đóng chặt chậm rãi mở ra. Đúng lúc Thượng Huyền Đạo tưởng kế hoạch đã thành, chương hé lộ linh hồn thật của Vương Lâm vẫn ẩn trong Thiên Nghịch châu, lạnh lùng quan sát mọi việc. Cuối chương, đầu lâu Tiên Tổ phát ra giọng nói của Thượng Huyền Đạo, tuyên bố giải phong ấn toàn bộ Điệu Vong tộc."},{"chuong":1889,"tieuDe":"Sự Tự Tin Của Tiên Hoàng!","tomTat":"Vương Lâm hé lộ rằng sau khi bị mắt phải nuốt vào, hắn đã giấu linh hồn trong Thiên Nghịch, giả như hồn bị diệt để quan sát kế hoạch của quốc sư. Hắn nhận ra quốc sư muốn dùng thân thể mình và Đạo Phi hóa thành hai mắt đầu tiên tổ, lừa pháp tắc để giải phong ấn cho toàn tộc, nhưng cũng bắt đầu nghi ngờ thân phận thật của người đang chiếm thân thể mình. Khi đầu tiên tổ sắp nói xong chữ cuối, giọt máu vàng của Tiên hoàng rơi xuống mi tâm cái đầu, phủ kín và chặn lời giải phong ấn, khiến quốc sư bị giữ trong mắt phải. Tiên hoàng Liên Đạo Chân xuất hiện cùng Song Tử Đại Thiên Tôn, tuyên bố đã nhìn thấu kế hoạch của quốc sư với Minh Đạo Tôn, Đạo Phi và Vương Lâm. Hắn tiết lộ kế hoạch thật của mình là dùng cái đầu tiên tổ như pháp bảo mạnh nhất của tiên tộc, khiến nó tỉnh lại để bản thân kế thừa tu vi tiên tổ trong lúc nguy cấp. Tiên hoàng điều khiển đầu tiên tổ phát kim quang đánh tan kiếm quang tím của Song Tử, nhưng Song Tử hợp thể thành nữ tử áo trắng và thi triển Tử Lâm Tín Thuật, gọi thiên thạch tím uy hiếp phá nát tổ thành nếu không giao Vương Lâm. Khi Tiên hoàng vẫn tự tin không thỏa hiệp, Cửu Đế Đại Thiên Tôn bước ra từ lỗ thủng trên trời, Hải Tử Thiên Tôn tái mặt đi theo, khiến thế cục xuất hiện biến số mới."},{"chuong":1890,"tieuDe":"Năm Đại Thiên Tôn!","tomTat":"Cửu Đế Đại Thiên Tôn hiện thân trong cấm cung, vạch rõ Tiên Hoàng đã lợi dụng khát vọng của quốc sư để đoạt quyền điều khiển đầu lâu Tiên Tổ và mưu tính hấp thu nó thành đầu của mình. Tiên Hoàng dùng đầu lâu thi triển Bát Cực Đạo, Cực Hóa Đạo và Tiên Hỏa Đạo, bức lui Cửu Đế cùng Song Tử, trong khi Vương Lâm vẫn ẩn trong mắt phải đầu lâu Tiên Tổ quan sát cục diện. Sau đó Tiên Hoàng dùng máu dẫn hư ảnh Tiên Tổ mặc hoàng bào và thanh kiếm vàng hiện ra, khiến Vương Lâm cảm nhận một lời kêu gọi sâu xa. Trước uy thế kim kiếm, Cửu Đế gọi Đạo Nhất và Võ Phong xuất hiện, bốn Đại Thiên Tôn cùng dùng thần thông đối kháng và phá tan đại kiếm chỉ chứa một thành lực lượng Tiên Tổ. Song Tử yêu cầu thả Vương Lâm, Cửu Đế yêu cầu phong ấn lại đầu lâu, Đạo Nhất và Võ Phong cũng muốn duy trì thế cục năm Đại Thiên Tôn. Tiên Hoàng không chịu thỏa hiệp, bộc phát kim quang từ thất khiếu để cưỡng ép hấp thu đầu lâu, nhưng phát hiện phong ấn Điệu vong tộc do quốc sư để lại trong đầu lâu đang ngăn hắn dung hợp."},{"chuong":1891,"tieuDe":"Quốc Sư Thật Sự!","tomTat":"Trong lúc bốn Đại Thiên Tôn bên ngoài dốc sức phá kim quang, Tiên Hoàng quyết định dùng máu thịt hậu nhân Tiên Tổ dẫn động phép tắc Thiên Cương để giải khai phong ấn Điệu Vong Tộc, tự hủy một phần cánh tay phải làm cái giá. Khi phong ấn tan đi, quốc sư giả đang chiếm thân thể Vương Lâm tưởng sứ mệnh đã hoàn thành nhưng lập tức bị sức mạnh Tiên Hoàng xóa sạch, trước khi chết mới nhớ ra mình chỉ là vỏ bọc, còn quốc sư thật là bé gái năm xưa. Sức mạnh Tiên Hoàng quét qua thân thể Vương Lâm nhưng không phát hiện linh hồn thật của hắn vì Thiên Nghịch Châu đã che phủ. Đúng lúc Tiên Hoàng bắt đầu hấp thu truyền thừa từ đầu Tiên Tổ, Hải Tử Thiên Tôn thức tỉnh ký ức và sức mạnh quốc sư chân chính của Điệu Vong Tộc, thu hồi kim quang và cắt đứt nguồn sức mạnh màu vàng. Hải Tử tự nhận là quốc sư, Cửu Đế xác nhận nàng là con gái mình và hé lộ Đại Hồn Môn vốn do một thiên tài Điệu Vong Tộc sáng tạo để truyền thừa kế hoạch chờ Vương Lâm xuất hiện. Trong khi mọi người bị cuốn vào chân tướng này, linh hồn Vương Lâm từ Thiên Nghịch Châu lan ra, đoạt lại thân thể và hiểu được cục diện thật sự."},{"chuong":1892,"tieuDe":"Trớ Thuật!","tomTat":"Cửu Đế công khai kế hoạch Điệu Vong Tộc kéo dài nhiều đời, nói thiên tài của tộc này từng giúp hắn thành Đại Thiên Tôn nên hắn phải trợ giúp kế hoạch giải phong ấn. Hải Tử được xác nhận có thân thể thuộc Đại Lục Tiên Cương nhưng linh hồn thuộc Điệu Vong Tộc, được linh hồn tộc nhân đã chết bảo vệ và nắm quyền hiệu lệnh linh miếu bảy mươi hai châu. Vương Lâm bị chỉ ra là mấu chốt vì kế hoạch cần một người đủ điều kiện đoạt xá bị hút vào đầu Tiên Tổ. Đạo Nhất và Vũ Phong thừa nhận từng biết kế hoạch nhưng không biết vai trò của Vương Lâm, còn Song Tử tuyên bố chỉ tới để mang Vương Lâm đi. Tiên hoàng vạch rõ Cửu Đế đã lợi dụng nhiều người, trong khi Cửu Đế hứa chia mắt, tai, đầu, não và tu vi Tiên Tổ cho các Đại Thiên Tôn để ép hắn dùng huyết mạch thí tổ. Trớ thuật Tiên Tổ được giải thích là nguyền rủa khiến kẻ hủy diệt thân thể Tiên Tổ phải chết, chỉ hậu nhân dùng huyết mạch lực mới phá được nhưng sẽ cắt đứt huyết mạch. Bên trong mắt phải đầu Tiên Tổ, Vương Lâm nghe toàn bộ chân tướng và nhớ tới vật lão tổ Đại Hồn Môn để lại cho mình sau ba trăm năm. Cuối chương, Tiên hoàng trầm mặc rồi giơ tay cách không nâng đầu Tiên Tổ bay lên."},{"chuong":1893,"tieuDe":"Vật Này, Người Này, Vương Mỗ Đều Muốn!","tomTat":"Vương Lâm ẩn trong đầu lâu Tiên Tổ, lặng quan sát Tiên Hoàng và các Đại Thiên Tôn tranh đoạt, đồng thời hiểu rằng nếu đầu lâu bị chém mở thì bản thân sẽ bại lộ. Tiên Hoàng không thỏa hiệp mà dùng huyết mạch làm đầu lâu nứt ra, giả vờ hấp thu sương vàng kim từ thất khiếu để dụ Cửu Đế, Đạo Nhất và Võ Phong cùng công kích. Hắn bất ngờ tự bạo thân thể Đại Thiên Tôn, khiến lực nổ hòa với thần thông của ba người, phá hủy cấm cung, địa cung, hoàng cung và làm vô số tu sĩ tan thành mây khói. Khe nứt trên đầu lâu Tiên Tổ mở rộng, Trớ Thuật phản phệ khiến Đạo Nhất và Võ Phong thối rữa, Cửu Đế cũng phải dốc sức chống đỡ. Linh hồn Tiên Hoàng nhân lúc hỗn loạn lao tới mắt trái đầu lâu, định đoạt xá Liên Đạo Phi để chia sẻ Trớ Thuật và lật ngược thế cờ. Đúng thời khắc ấy, Vương Lâm từ mắt trái bước ra, không bị Trớ Thuật ảnh hưởng, vung tay áo thu linh hồn Tiên Hoàng vào không gian trữ vật. Hắn dìu Liên Đạo Phi hôn mê rời khỏi mắt trái, đứng giữa đầu lâu Tiên Tổ đang nứt vỡ và tuyên bố cả vật lẫn người đều thuộc về mình."},{"chuong":1894,"tieuDe":"Làm Càn!","tomTat":"Vương Lâm xuất hiện sau biến cố Tiên Hoàng tự bạo và đầu lâu Tiên Tổ được mở, khiến Cửu Đế nhận ra kế hoạch của mình liên tiếp sai lệch vì Vương Lâm không chết mà còn nhìn như tăng tiến. Đạo Nhất vì đau đớn và phẫn nộ lao tới công kích, nhưng bị lưới sát lục lôi đình màu đen của Vương Lâm đẩy lui, làm Trớ Thuật trong thân thể nặng thêm. Cửu Đế vừa dụ vừa dọa, hứa để Vương Lâm rời đi an toàn và trợ hắn thành Đại Thiên Tôn nếu giao đầu lâu, đồng thời cảnh cáo các Đại Thiên Tôn có thể nghiền nát hắn. Song Tử Đại Thiên Tôn đến cạnh Vương Lâm trong trạng thái suy yếu, được Vương Lâm lấy hai con ngươi Tiên Tổ trao cho để đáp lại việc tương trợ. Cửu Đế nổi giận gọi Đạo Nhất, Võ Phong và Hải Tử cùng ra tay, còn Song Tử tái dung hợp thành hình thái chính thức để cản Cửu Đế và Đạo Nhất. Vương Lâm tiếp tục chém hai tai Tiên Tổ trao cho Võ Phong, khiến Võ Phong nhận được vật cần thiết rồi rút lui khỏi cuộc chiến. Cửu Đế thi triển lực lượng thái dương gọi bạch lang đối kháng Song Tử, trong khi Đạo Nhất dù toàn lực vẫn bị Trớ Thuật làm suy yếu. Cuối chương, Vương Lâm quay sang Hải Tử, nhắc việc Điệu Vong tộc từng lợi dụng hắn giải phong ấn và đề nghị xóa bỏ ân oán nếu nàng không tham chiến."},{"chuong":1895,"tieuDe":"Đại Thiên Tôn Chi Dương!","tomTat":"Hải Tử Thiên Tôn chọn đứng ngoài không ra tay, còn Cửu Đế tiếp tục bị Song Tử cuốn vào trận chiến cấp Đại Thiên Tôn. Đạo Nhất mang sát khí lao tới giết Vương Lâm để rửa nhục, nhưng Vương Lâm tóc đen bộc phát chiến ý, lấy mảnh vỡ Tiên Cực kiếm và tách các bổn nguyên ra ngoài. Mảnh vỡ Tiên Cực kiếm khiến Kim bổn nguyên đại thành, hoàn tất ngũ hành và làm ngũ hành chân thân bộc phát lực lượng năm màu phối hợp cùng bản thể tóc đen áp chế Đạo Nhất. Trớ Thuật trong cơ thể Đạo Nhất bùng phát thiêu đốt linh hồn, khiến hắn cảm nhận nguy cơ tử vong và muốn rời khỏi chiến trường. Vương Lâm dùng cấm chế bổn nguyên, thái sơ bổn nguyên và tam đại hư bổn nguyên phong tỏa thiên địa, buộc Đạo Nhất phải thiêu đốt lực lượng bản thể phá vây bỏ chạy. Cửu Đế cố thoát khỏi Song Tử để cứu Đạo Nhất, còn Song Tử khựng lại khi bị nhắc tới thân phận tiên tộc và cái chết của Tiên Hoàng. Cuối chương, Vương Lâm dung hợp ngũ hành chân thân cùng các bổn nguyên trở lại, thành trạng thái nửa đen nửa trắng và làm hiện hư ảnh Đại Thiên Tôn Chi Dương sau lưng, khiến các Đại Thiên Tôn chấn động."},{"chuong":1896,"tieuDe":"Lưu Lại Đạo Phi!","tomTat":"Sau khi Đại Thiên Tôn Chi Dương hai nửa đen trắng hiện sau lưng, Vương Lâm lao tới truy sát Đạo Nhất, buộc Cửu Đế phải ra tay ngăn cản để tiên tộc không mất thêm một Đại Thiên Tôn. Cửu Đế hóa mặt trời trắng thành bạch lang nhưng bị một cước của Vương Lâm đá sụp hơn phân nửa, còn Vương Lâm cũng thổ huyết rồi tiếp tục truy kích. Đạo Nhất bị Trớ Thuật bộc phát toàn diện, dùng loan đao màu đen muốn đồng quy vu tận nhưng bị Vương Lâm hóa chín mươi chín hư ảnh vượt qua, điểm chỉ đánh rơi xuống đất và dẫm ngực để ra giá. Hài Tử mượn lực lượng Điệu Vong tộc tạo sóng gợn màu lam cứu Đạo Nhất, song Vương Lâm vẫn xuyên tơ đen qua, ép Đạo Nhất giao đầu lâu trẻ con tràn tử khí rồi để hắn trốn đi. Cửu Đế lộ rằng mình cùng Điệu Vong tộc từng bố cục quanh di vật Tiên Tổ, dự định để Đại Thiên Tôn tiên tộc chia sẻ di vật nhằm xóa bỏ Tiên Hoàng nhất mạch, nhưng lợi lớn nay rơi vào tay Vương Lâm. Vì cảm thấy nợ Song Tử, Vương Lâm quyết sẽ dùng toàn lực ngăn cuộc chiến giữa cổ tộc và tiên tộc để nàng không phải hối hận. Cuối chương, Cửu Đế cho phép Vương Lâm mang đầu lâu Tiên Tổ đi nhưng tuyệt đối cấm mang Liên Đạo Phi, và ngay cả Song Tử cũng khuyên Vương Lâm lưu Liên Đạo Phi lại."},{"chuong":1897,"tieuDe":"Khúc Chung Nhân Tán Không Sầu Mạc!","tomTat":"Vương Lâm ban đầu không định nghe uy hiếp của Cửu Đế, nhưng vì món nợ với Song Tử nên buộc phải nghe Hài Tử và Song Tử giải thích lý do Liên Đạo Phi phải ở lại. Hài Tử nói đầu tiên tổ vốn trấn áp linh hồn bảy mươi hai châu, còn Liên Đạo Phi có huyết mạch và một phần truyền thừa tu vi tiên tổ nên được chọn làm vật thay thế. Khi biết đầu tiên tổ đã bị chia cắt và không thể khôi phục tác dụng, Vương Lâm đau khổ thu đầu tiên tổ vào không gian trữ vật, để Liên Đạo Phi lại và thề lần sau trở về hoàng cung tiên tộc sẽ cứu hắn ra. Hài Tử thi triển bí thuật mở dấu ấn, khiến Liên Đạo Phi tỏa kim quang, trở thành Đại Thiên Tôn thứ năm của tiên tộc sau Tiên Hoàng nhưng vĩnh viễn ngủ say để trấn áp bảy mươi hai châu. Cấm cung khôi phục, kim quang quanh Liên Đạo Phi hóa thành một ngọn núi màu vàng thay cho chín ngọn núi trước đó, còn Vương Lâm trở lại hoàng cung Trung Châu đã thành phế tích. Song Tử chia tay Vương Lâm, nói nàng có hai mắt tiên tổ và sẽ về Tử Dương Tông bế quan, còn Vương Lâm quyết định quay lại Đại Hồn Môn một chuyến rồi rời tiên tộc. Cuối chương, Hài Tử buồn bã nhìn theo Vương Lâm, trong khi Cửu Đế bị hắc khí Trớ Thuật lan tràn nhưng vẫn khuyên nàng về sau nên kết giao với hắn."},{"chuong":1898,"tieuDe":"Lời Khẩn Cầu Tới Từ Năm Tháng Vạn Cổ!","tomTat":"Sau biến cố hoàng cung, Cửu Đế áp chế tin Tiên Hoàng Liên Đạo Chân mất mạng, để bên ngoài chỉ biết Tiên Hoàng lại bế quan. Võ Phong trở về sông băng Bắc châu tự đóng băng để hóa giải Trớ Thuật, Đạo Nhất cưỡng ép thuộc hạ phân tán nguyền rủa khiến Đạo Nhất Tông gần như thành tử tông, còn Cửu Đế nhờ Hài Tử trợ giúp để chậm rãi tiêu tán hắc khí. Song Tử không trúng Trớ Thuật nên về Tử Dương tông dung hợp hai mắt Tiên Tổ, trong khi Liên Đạo Phi vẫn ngủ dưới núi vàng trong địa cung hoàng cung. Nửa năm sau, Vương Lâm tới Đại Hồn Môn ở Thiên Ngưu Châu, thấy tông môn vẫn yên bình nhưng nhận ra nơi này ẩn chứa kế hoạch sâu xa của thiên tài Điệu Vong tộc. Hắn lặng lẽ nhìn các cố nhân như Thanh Ngưu chân nhân, Viêm Loan, Phàn San Lộ, Phàn San Mộng và Đồ Thanh rồi tiến vào Tàng Hồn các, vượt qua các tầng cấm chế đến tầng chín có ngọc giản thần thông. Trên tầng mười, Vương Lâm thấy vật lão tổ Đại Hồn Môn để lại cho mình và rời đi sau khi nói chuyện bị lợi dụng đã xóa bỏ với Hài Tử. Cuối chương hé lộ trong tầng mười có pho tượng Vương Lâm cùng bộ hài cốt nhốt linh hồn lão tổ Đại Hồn Môn, quỳ dâng não và tim để cầu xin tha thứ qua vô số năm."},{"chuong":1899,"tieuDe":"Biển","tomTat":"Chương mở ra bằng địa lý Đại Lục Tiên Cương: tiên tộc có bảy mươi hai châu, cổ tộc có ba mươi sáu quận, giữa hai bên là vùng biển vô tận quanh năm sóng gió và sương mù, trở thành vách ngăn tự nhiên khiến tiên cổ khó qua lại. Ở phương bắc Bắc Châu, Hàn Châu gần như toàn tuyết, hàn khí nặng đến mức sinh linh hiếm thấy, là điểm cuối trước khi ra biển. Vương Lâm dẫn Hứa Lập Quốc và Lưu Kim Bưu đi trong gió tuyết; Hứa Lập Quốc mặc nhiều lớp áo bông, khoe khoang bảo y chống lạnh và châm chọc Lưu Kim Bưu đang rét run, còn Lưu Kim Bưu nhờ con rắn nhỏ hình rồng trên vai thở khí giúp chống chịu. Vương Lâm nhìn thấu tâm tư hai thuộc hạ, đề nghị thu Lưu Kim Bưu vào không gian trữ vật nhưng hắn từ chối vì sợ Hứa Lập Quốc ở riêng với chủ nhân, nên Vương Lâm buộc Hứa Lập Quốc chia vài bộ áo. Khi hàn khí càng nặng, Vương Lâm cuốn cả hai tới biên giới Hàn Châu rồi thu Hứa Lập Quốc và Lưu Kim Bưu vào không gian trữ vật. Một mình đứng trên khối băng trôi giữa biển, hắn ngoái nhìn vùng đất tiên tộc, nhớ chuyện cũ và những khuôn mặt quen thuộc, sau đó nhắc tới Liên Đạo Phi rồi hướng về Huyền La sư tôn ở phía cổ tộc và biến mất khỏi khối băng."},{"chuong":1900,"tieuDe":"Đường Lối","tomTat":"Vương Lâm cưỡi Hải Long rời tiên tộc, vượt vùng biển mênh mông để hướng về cổ Tộc, không dùng súc địa thành thốn mà vừa đi vừa điều tức. Hắn quyết định tới hoàng thành Đạo Cổ, muốn yên lặng tu hành và hoàn thành lời hứa với Huyền La là bảo vệ Đạo Cổ nhất mạch cùng chuyển thế của sư tôn. Trên đường, hắn tiếc nuối vì chưa tìm được Thanh Thủy, Tư Đồ và Lý Thiến Mai, đồng thời đau thương nhớ Lý Mộ Uyển vì một tia hồn phách của nàng vẫn chưa rõ tung tích. Khi kiểm lại bảo vật, hắn lấy huyết kiếm ra, nhận ra kiếm thuộc Đạo Cổ và Diệp Mịch, phá tầng phong ấn khiến sát khí bùng lên và nhớ lời hứa tìm hậu nhân Diệp Mịch. Chương xác nhận sau biến cố tiên tộc, kim bổn nguyên đại thành và ngũ hành chân thân quy nhất đã đưa tu vi Vương Lâm lên Không Kiếp hậu kỳ, chiến lực đạt mức đệ nhất nhân dưới Đại Thiên Tôn nếu đối phương không thiêu đốt lực lượng. Hắn vạch đường tu hành tiếp theo là hoàn thiện ngũ hành chân thân, sát lục lôi đình chân thân và các hư bổn nguyên, đồng thời nghiên cứu đầu lâu Tiên Tổ để khiến Đại Thiên Tôn Chi Dương ngưng thật. Trong không gian trữ vật, sợi tóc bạc và đầu lâu nhỏ tràn tử khí vẫn khiến hắn thấy quen thuộc mà chưa rõ lai lịch. Sau mấy tháng vượt qua vùng pháp tắc ngăn cách tiên cổ, Văn Thú bay theo vui sướng và Vương Lâm nhìn thấy vùng đất màu đen của cổ Tộc hiện ra phía xa."},{"chuong":1901,"tieuDe":"Sứ Đoàn Đạo Cổ","tomTat":"Chương mở ra vùng đất cổ tộc với hắc thổ mênh mông, khí chất thô cuồng và chế độ hoàng quyền tuyệt đối khác hẳn tiên tộc. Cổ tộc được chia thành ba quốc gia Đạo cổ, Cực cổ và Thủy cổ; dù Đại Thiên Tôn có tu vi tối cao, họ vẫn bị phong ấn vạn cổ và thánh địa cổ tộc ràng buộc, không thể làm hại cổ hoàng. Vương Lâm đặt chân lên đất cổ tộc, nhớ tới hiểu biết từ Huyền La và sách cổ của Song Tử Đại Thiên Tôn, nhưng vì thiếu bản đồ đi Đạo cổ nên quyết định tìm ngọc giản trước. Hắn tới gần Hắc Thạch Thành, nơi đang chuẩn bị đóng cổng và cấm thành ba ngày theo lệnh thành chủ. Khi bị hai đại hán Cổ Thần năm tinh chất vấn thân phận, Vương Lâm hiển lộ chín tinh điểm trên mi tâm, khiến toàn bộ binh sĩ kính sợ gọi hắn là thần thánh đại nhân. Một đại hán dâng ngọc giản bản đồ sơ lược, giúp hắn biết Hắc Thạch Thành ở rìa Mộc Tang Quận thuộc Thủy cổ. Qua lời binh sĩ, Vương Lâm biết Hắc Thạch Thành đang nghênh đón hoàng tử và sứ đoàn Đạo Cổ, đoàn đã nhiều năm tìm mỹ nữ khắp cổ tộc vì tin hoàng đế Đạo cổ muốn chọn phi tần."},{"chuong":1902,"tieuDe":"Kế Đô Hoàng Tử","tomTat":"Ngoài Hắc Thạch thành, Vương Lâm nghe đại hán nói việc phong thành liên quan tới Kế Đô hoàng tử và sứ đoàn Đạo Cổ, từ đó nảy ý ở lại để hỏi tin mười hai quận Đạo Cổ. Thành chủ Lương Vân mặc kim giáp dẫn Khổng Ti, Mạch Lạc và gần một ngàn binh sĩ ra ngoài thành, chú ý tới chín tinh điểm trên mi tâm Vương Lâm rồi khách khí mời hắn cùng chờ. Trong lúc trò chuyện, Lương Vân và Mạch Lạc nhắc tới giai đoạn dung yêu luyện ma cùng hệ thống thông, dung, luyện, khiến Vương Lâm nhận ra mình còn thiếu hiểu biết về tu luyện cổ tộc sau đệ nhị tôn. Bầu trời bị xé mở, cổ Yêu Đà Lạc mấy vạn trượng xuất hiện, trên đầu chở Kế Đô hoàng tử và một nữ tử áo lam, khiến mọi người trong ngoài thành đồng loạt quỳ lạy. Vương Lâm là người duy nhất vẫn đứng, làm Lương Vân, Khổng Ti và Mạch Lạc kinh hãi. Sau đó một cổ Ma vạn trượng chở bảy người xuất hiện, nhóm này chào Kế Đô hoàng tử rồi cũng chú ý tới Vương Lâm. Kế Đô hoàng tử coi việc Vương Lâm không quỳ là bất kính, hỏi Lương Vân vài câu rồi trực tiếp ra lệnh cho Đà Lạc giết hắn. Đà Lạc gầm thét, vung bàn tay khổng lồ với móng sắc hóa thành hắc tuyến và yêu khí ngập trời chụp xuống Vương Lâm."},{"chuong":1903,"tieuDe":"Người Con Gái Tên Tống Trí!","tomTat":"Vương Lâm chứng kiến hoàng quyền Thủy Cổ khiến cả thành quỳ lạy và cảm thấy mình khó hòa hợp với trật tự Cổ Tộc. Khi Cổ Yêu của Kế Đô chụp xuống, hắn bình tĩnh bước xuyên qua như thân ảnh trong suốt, khiến Khổng Ti, Ma Thánh, Kế Đô và Lương Vân đều chấn động. Chỉ bằng ánh mắt và một câu chất vấn, Vương Lâm làm Cổ Yêu từ điên cuồng chuyển sang sợ hãi rồi quỳ phục. Hắn tiếp tục tiến tới Cổ Ma của sứ đoàn Đạo Cổ, khiến Cổ Ma phủ phục và ép Diệp Hải cùng sáu người còn lại lộ lực lượng. Diệp Hải tự xưng được Đạo Cổ Hoàng ban danh, nói sứ đoàn tới Thủy Cổ Quốc tuyển phi và giao ngọc giản bản đồ Đạo Cổ hoàng thành cho Vương Lâm. Kế Đô hoàng tử đổi thái độ, xin bồi thường và sai Lương Vân mời Tống Trí ra để đi theo sứ đoàn. Tống Trí mặc áo xanh xuất hiện với khí chất thanh thuần, ngẩng đầu nhìn Vương Lâm, ánh mắt hai người gặp nhau giữa không trung."},{"chuong":1904,"tieuDe":"Một Chiếc Lá Che Mắt","tomTat":"Ngoài Hắc Thạch Thành, nữ tử áo xanh Tống Trí xuất hiện và được Kế Đô xác nhận là người họ Tống thuộc phân chi xa của Đại Thiên Tôn Tống gia nhất mạch. Nàng bị giao cho Đạo Cổ sứ đoàn đi tuyển phi, trong lòng lưu luyến quê hương và mong không bị chọn trúng. Sau khi sứ đoàn cưỡi Cổ Ma rời đi, Kế Đô chuyển sang cung kính với Vương Lâm, hỏi tên và mời hắn tới hành cung U Quận. Trước khi rời Hắc Thạch Thành, Kế Đô truyền âm phong khẩu Lương Vân, Khổng Ti và thanh niên mặc áo đen, cấm để lộ mọi chuyện về Vương Lâm. Tại U Quận, Kế Đô giới thiệu Đại Cổ Yêu của mình vốn là chiến sĩ cấm vệ Thủy Cổ từng dung hợp hai mươi bảy tinh nhưng thất bại nên thoái hóa mất thần trí. Trong đại điện hành cung, Kế Đô bái kiến Vương Lâm bằng danh hiệu Bạch Phát Dược Thiên Tôn và đưa ngọc giản danh sách cao thủ Tiên Tộc cho hắn xem. Vương Lâm nhận ra trong danh sách ấy, hình của mình cùng năm Đại Thiên Tôn phát kim quang, cho thấy Cổ Tộc đã xếp hắn vào hàng cao thủ đặc biệt trọng yếu."},{"chuong":1905,"tieuDe":"Đường Lui!","tomTat":"Vương Lâm cầm ngọc giản bản đồ và nhận ra Kế Đô đã sớm nghi ngờ thân phận mình từ lần gặp ở Hắc Thạch Thành, thậm chí cố ý để Đại Cổ Yêu ra tay nhằm nghiệm chứng. Kế Đô nói rõ hắn đã nối Bạch Phát Dược Thiên Tôn của Tiên Tộc với đệ tử duy nhất của Huyền La Đại Thiên Tôn nhờ suy đoán từ Đạo Cổ, phụ hoàng và Tống Thiên Đại Thiên Tôn. Hoàng muội song sinh của Kế Đô lộ diện trong cuộc đối thoại, chứng kiến huynh trưởng quỳ xuống xin nhận Vương Lâm làm nghĩa phụ để tranh lấy trợ lực trong cuộc đoạt ngôi Thủy Cổ Hoàng. Vương Lâm không tin mọi việc là ngẫu nhiên, ép Kế Đô khai ra quốc sư Thủy Cổ là cậu ruột đã dùng tính mạng bói một quẻ, chỉ hắn đi cùng sứ đoàn Đạo Cổ để gặp cơ hội đổi vận rồi tự tuyệt. Kế Đô dâng tổ giản phong ấn lực lượng một chỉ của Cổ Tổ cùng ống dịch chứa mộc bản nguyên tinh thuần, muốn dùng lễ trọng chứng minh thành ý. Vương Lâm chưa chính thức nhận lời làm nghĩa phụ, nhưng yêu cầu ngọc giản liên lạc, thu lễ vật và tự quyết giữ lại một đường lui nếu sau này rời Đạo Cổ. Sau khi Vương Lâm rời đi, Kế Đô tin Đạo Cổ Hoàng không giữ nổi một cường giả như hắn và cho rằng mình đã đặt cược đúng."},{"chuong":1906,"tieuDe":"Một Vái Lư Hương, Hoàng Tôn Biến Sắc","tomTat":"Đạo Cổ nhất mạch nằm ở tây nam đại lục, địa bàn mười hai quận rộng lớn, sứ đoàn Đạo Cổ nhờ các tồn tại Đại Cổ Thần, Đại Cổ Yêu, Đại Cổ Ma xé trời di chuyển nên đã trở về Đạo Cổ hoàng thành. Một tháng sau, Vương Lâm dựa vào ngọc giản bản đồ từ Thủy Cổ nhất mạch tới Thiên Không Thành, quan sát pho tượng Cổ Tổ, hoàng cung tử khí và cấm chế phòng hộ dày đặc. Theo quy tắc, người vào thành cần ngọc giản thân phận, còn trong nhận thức Đạo Cổ chỉ Tiên Cương Cửu Dương có thể tự do ra vào ba hoàng thành Cổ Tộc, nhưng Vương Lâm hóa như sương khói xuyên qua cấm chế không bị ngăn. Hắn cảm nhận khí tức Huyền La ở ngọn núi phía nam, đi tới Đạo Cổ Điện, nơi tộc nhân Đạo Cổ cầu cơ hội đột phá và được chín cường giả luân phiên khai linh tính, thân thể. Trước lư hương ngoài điện, Vương Lâm vái không phải vái lư hương mà vái sư tôn Huyền La, xác nhận bản thân đã chọn theo Đạo Cổ và muốn bảo vệ Đạo Cổ cùng sư tôn chuyển thế. Một vái của hắn khiến lư hương nổ vang, chín cây hương cháy dữ dội, khói xanh dày gấp vô số lần phủ khắp Thiên Không Thành, làm Đạo Cổ Hoàng trong hoàng cung ra lệnh tra xét rồi biến sắc khi thấy khói xanh khom mình như sắp sụp đổ. Huyền La truyền âm gọi Tiểu Vương, ngăn hắn vái tiếp và bảo đi hậu sơn, nhờ vậy Vương Lâm đứng thẳng dậy còn khói xanh dần khôi phục bình thường."},{"chuong":1907,"tieuDe":"Nhất Bôi Nhiệt Trà Noàn Như Gia","tomTat":"Trong Đạo Cổ hoàng thành, Đạo Cổ Hoàng Diệp Đạo cảm nhận khí tức Hồn Huyết, nhớ tới một suy đoán ám ảnh nhiều năm và ra lệnh đẩy nhanh việc dung hợp linh hồn nhóm phi tử vừa tuyển. Vương Lâm xuất hiện trước Đạo Cổ Điện nhưng được đưa tới đào viên phía sau, nơi Huyền La đã tự tay chuẩn bị trà chờ đệ tử trở về. Chén trà khiến Vương Lâm cảm nhận sự ấm áp như gia đình, còn Huyền La nói ông vẫn âm thầm chú ý mọi chuyện của hắn tại Tiên Tộc nhưng không thể tới đón vì lo bị các Đại Thiên Tôn phát hiện. Vương Lâm nhắc lại lời hứa bảo vệ Đạo Cổ nhất mạch và quyết định ở lại cho tới khi hoàn thành hứa hẹn với sư tôn. Ba ngày sau, Huyền La dẫn Vương Lâm tới trước Đạo Cổ Điện, giao chín cường giả Đạo Cổ dưới trướng cho hắn nghe lệnh và khiến họ bái kiến hắn là Thiếu Thiên Tôn. Đạo Cổ Hoàng giáng lâm trong tử khí cùng gần trăm cường giả Cổ Thần, Cổ Yêu, Cổ Ma và hai lão già khí tức không kém Dược Thiên Tôn. Trước mặt Diệp Đạo, Huyền La công khai Vương Lâm là Bạch Phát Dược Thiên Tôn, đệ tử của mình, về sau sẽ thay ông bảo vệ Đạo Cổ khi ông chuyển thế và có quyền chọn tân hoàng tôn nếu hoàng tôn thoái vị. Ngay sau đó, một lão già bên cạnh Đạo Cổ Hoàng viện tộc quy buộc Vương Lâm quỳ lạy, mở ra xung đột trực diện giữa thân phận đệ tử Đại Thiên Tôn và lễ nghi hoàng quyền Đạo Cổ."},{"chuong":1908,"tieuDe":"Sư Tôn Như Cha!","tomTat":"Trước Đạo Cổ Điện, Thường Thị nhân danh quy củ Đạo Cổ ép Vương Lâm phải quỳ trước Đạo Cổ hoàng tôn, khiến bầu không khí lập tức căng thẳng vì hoàng quyền nơi Cổ Tộc được xem là tối cao. Đạo Cổ hoàng tôn trong lòng ghen ghét Vương Lâm vì được Huyền La nhận làm đệ tử, có mười giọt máu Cổ Tổ, Hồn Huyết và danh hiệu Bạch Phát Dược Thiên Tôn, nhưng ngoài mặt lại giữ vẻ ban ân. Vương Lâm dùng ánh mắt và huyết mạch khiến Thường Thị sợ hãi, sau đó Đạo Cổ hoàng tôn tuyên bố hắn là người bảo vệ tương lai của Đạo Cổ, thân phận ngang hàng mình ngoài một vài đại điển, đồng thời ban ngọc bội tím cho phép ra vào hoàng cung. Khi trở về hoàng cung, Đạo Cổ hoàng tôn lộ rõ ý định chờ Huyền La chuyển thế rồi dùng quyền lực bắt Vương Lâm quỳ và giết hắn. Huyền La vì thấy đệ tử chịu oan ức nên cho Vương Lâm quyền rời khỏi Đạo Cổ, nhưng Vương Lâm khẳng định vẫn tiếp tục lời hứa bảo vệ Đạo Cổ nhất mạch. Sau đó Huyền La đưa Vương Lâm tới Bình Thiên Quận, giới thiệu đầm lầy cổ chiến trường chứa sát khí có thể nuôi lớn sát lục bản nguyên, rồi nói còn nhiều nơi bản nguyên khác đã được ông thương lượng để Vương Lâm vào tu hành. Cuối chương, Huyền La cho biết sẽ dẫn Vương Lâm bái kiến Cổ Đạo Đại Thiên Tôn, người trấn nhiếp Tiên Tộc và có thể mang lại cơ duyên lớn cho hắn."}];
